select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = pl.relatedpostid and b.userid = u.id and c.userid = u.id and p.id = v.postid and p.id = c.postid and p.id = ph.postid and c.score=0 and c.creationdate>=timestamp '2010-07-26 17:09:48' and p.posttypeid=1 and p.answercount>=0 and p.commentcount>=0 and p.commentcount<=14 and pl.creationdate>=timestamp '2010-10-27 10:02:57' and pl.creationdate<=timestamp '2014-09-04 17:23:50' and ph.creationdate<=timestamp '2014-09-11 20:09:41' and v.creationdate>=timestamp '2010-07-21 00:00:00' and v.creationdate<=timestamp '2014-09-14 00:00:00';
